blocks.body:
{
    "level": "A2–B1",
    "intro": "W tym temacie poznasz <strong>pozycję przysłówków</strong> w zdaniach angielskich: przysłówki częstotliwości, trybu działania, miejsca, czasu i stopnia.",
    "rules": [
        {
            "label": "Częstotliwość",
            "color": "emerald",
            "text": "<strong>Zawsze, często, nigdy</strong> — przed czasownikiem głównym, potem:",
            "example": "Ona zawsze je śniadanie."
        },
        {
            "label": "Sposób",
            "color": "blue",
            "text": "<strong>Szybko, dobrze, ostrożnie</strong> — na końcu zdania:",
            "example": "Mówi biegle po angielsku."
        },
        {
            "label": "Miejsce + Czas",
            "color": "amber",
            "text": "<strong>Kolejność:</strong> Sposób → Miejsce → Czas:",
            "example": "W zeszłym roku ciężko pracowała w Londynie."
        }
    ]
}

{
    "title": "1. Trzy pozycje przysłówków",
    "intro": "Przysłówki mogą zajmować trzy główne pozycje w zdaniu:",
    "items": [
        {
            "label": "Przód",
            "title": "Na początku",
            "subtitle": "Przed podmiotem: Wczoraj spotkałem mojego przyjaciółka."
        },
        {
            "label": "Środek",
            "title": "W środku",
            "subtitle": "Między podmiotem a czasownikiem: Ona zawsze pije kawę."
        },
        {
            "label": "Koniec",
            "title": "W end",
            "subtitle": "Po czasowniku/przysłówku: Mówi biegle po angielsku."
        }
    ]
}

{
    "title": "2. Przysłówki częstotliwości",
    "sections": [
        {
            "label": "Przed czasownikiem głównym",
            "color": "emerald",
            "description": "Przysłówki <strong>zawsze, zwykle, często, czasami, rzadko, nigdy</strong> są umieszczane <strong>przed</strong> czasownikiem głównym.",
            "examples": [
                {
                    "en": "Ona zawsze je śniadanie.",
                    "ua": "Ona zawsze ma śniadanie"
                },
                {
                    "en": "Często chodzę na siłownię.",
                    "ua": "Często chodzę na siłownię."
                },
                {
                    "en": "Oni nigdy nie piją kawy.",
                    "ua": "Nigdy nie piją kawy.[[[CODX_4]]]Po czasowniku TO BE"
                }
            ]
        },
        {
            "label": "Після дієслова TO BE",
            "color": "sky",
            "description": "Jeśli czasownik <strong>być</strong>, przysłówek częstotliwości umieszcza się <strong>po</strong> nim.",
            "examples": [
                {
                    "en": "On zawsze się spóźnia.",
                    "ua": "On zawsze się spóźnia."
                },
                {
                    "en": "Ona zwykle jest szczęśliwa.",
                    "ua": "Ona zwykle jest szczęśliwa."
                },
                {
                    "en": "Oni rzadko się nudzą.",
                    "ua": "Rzadko się nudzą."
                }
            ]
        },
        {
            "label": "Po czasowniku posiłkowym",
            "color": "amber",
            "description": "W czasach złożonych przysłówek występuje <strong>po</strong> czasowniku posiłkowym.",
            "examples": [
                {
                    "en": "Nigdy nie byłem w Paryż.",
                    "ua": "Nigdy nie byłam w Paryżu."
                },
                {
                    "en": "Zawsze chciała mieć psa.",
                    "ua": "Zawsze chciała mieć psa."
                },
                {
                    "en": "Zazwyczaj docierają na czas.",
                    "ua": "Zazwyczaj docierają na czas czas."
                }
            ],
            "note": "<strong>Czasami, zwykle, często</strong> może występować na początku akcentu."
        }
    ]
}

{
    "title": "3. Przysłówki manier",
    "sections": [
        {
            "label": "Na końcu zdania",
            "color": "emerald",
            "description": "Przysłówki <strong>szybko, powoli, ostrożnie, cóż, źle, pięknie</strong> zwykle stoją <strong>na końcu</strong> zdania.",
            "examples": [
                {
                    "en": "Śpiewa pięknie.",
                    "ua": "Ona jest pięknie śpiewa."
                },
                {
                    "en": "Szybko ukończył test.",
                    "ua": "Szybko ukończył test."
                },
                {
                    "en": "Ciężko pracują każdego dnia.",
                    "ua": "Ciężko pracują każdego dnia."
                }
            ]
        },
        {
            "label": "Po przysłówku",
            "color": "sky",
            "description": "Jeśli występuje przysłówek, przysłówek oznaczający czynność znajduje się <strong>po</strong> nim.",
            "examples": [
                {
                    "en": "Ona mówi płynnie po angielsku.",
                    "ua": "Ona mówi po angielsku płynnie."
                },
                {
                    "en": "Dobrze gra na pianinie.",
                    "ua": "Dobrze gra na pianinie."
                },
                {
                    "en": "Wykonali tę pracę starannie.",
                    "ua": "Wykonali tę pracę starannie."
                }
            ],
            "note": "❌ <em>Ona mówi płynnie po angielsku</em> źle!"
        }
    ]
}

{
    "title": "4. Tutaj przysłówki miejsca (przysłówki miejsca).",
    "sections": [
        {
            "label": "В кінці речення",
            "color": "emerald",
            "description": "Обставини <strong>here, there, at home, in the park, at school</strong> стоять <strong>в кінці</strong> речення.",
            "examples": [
                {
                    "en": "She lives here.",
                    "ua": "Вона живе тут."
                },
                {
                    "en": "Pracuje w biurze.",
                    "ua": "Pracuje w biurze."
                },
                {
                    "en": "Dzieci bawią się w parku.",
                    "ua": "Dzieci bawią się w parku park."
                }
            ]
        },
        {
            "label": "Na początku dla podkreślenia",
            "color": "sky",
            "description": "W stylu formalnym lub dla podkreślenia okoliczności związane z miejscem mogą być na początku.",
            "examples": [
                {
                    "en": "Oto twoja książka.",
                    "ua": "Oto twoja książka."
                },
                {
                    "en": "To idzie autobus.",
                    "ua": "Tutaj jedzie autobus."
                }
            ]
        }
    ]
}

{
    "title": "5. Przysłówki czasu",
    "sections": [
        {
            "label": "Na końcu zdania",
            "color": "emerald",
            "description": "Przysłówki czasu (<strong>wczoraj, dzisiaj, jutro, ostatni tydzień, codziennie</strong>) zwykle znajdują się <strong>na końcu</strong>.",
            "examples": [
                {
                    "en": "Budzę się o 6:00 godzina.",
                    "ua": "Budzę się o szóstej."
                },
                {
                    "en": "Ona uczy się angielskiego codziennie.",
                    "ua": "Na co dzień uczy się angielskiego."
                },
                {
                    "en": "Wczoraj byliśmy w kinie.[[[CODX_1]]]Wczoraj byliśmy w kinie. przyjaciółka.",
                    "ua": "Ми ходили в кіно вчора ввечері."
                }
            ]
        },
        {
            "label": "На початку для акценту",
            "color": "sky",
            "description": "Для акценту обставини часу можна поставити <strong>на початку</strong>.",
            "examples": [
                {
                    "en": "Yesterday, I met an old friend.",
                    "ua": "Wczoraj spotkałam starą przyjaciółkę.[[[CODX_6]]]Każdego ranka ona biegnie w parku. pierwszy."
                },
                {
                    "en": "Every morning, she jogs in the park.",
                    "ua": "Щоранку вона бігає в парку."
                }
            ]
        },
        {
            "label": "Кілька обставин часу",
            "color": "amber",
            "description": "Якщо є кілька обставин часу, більш специфічна йде першою.",
            "examples": [
                {
                    "en": "Wyjeżdża o 10 rano w poniedziałek.",
                    "ua": "Wyjeżdża o 10 rano w poniedziałek."
                }
            ]
        }
    ]
}

{
    "title": "6. Kolejność okoliczności (sposób → miejsce → czas)",
    "intro": "Jeśli na końcu zdania znajduje się kilka okoliczności, kolejność jest następująca:",
    "rows": [
        {
            "en": "Sposób",
            "ua": "Jak?",
            "note": "mocno, szybko, cóż"
        },
        {
            "en": "Miejsce",
            "ua": "Gdzie?",
            "note": "w Londynie, w domu, tutaj"
        },
        {
            "en": "Czas",
            "ua": "Kiedy?",
            "note": "wczoraj, w zeszłym roku, co roku dzień"
        }
    ],
    "warning": "📌 Przykład: <strong>W zeszłym roku ciężko pracowała w Londynie.</strong>"
}

{
    "title": "7. Przysłówki stopnia",
    "sections": [
        {
            "label": "Przed przymiotnikiem/przysłówkiem",
            "color": "emerald",
            "description": "Przysłówki <strong>bardzo, całkiem, naprawdę, niezwykle, dość</strong> stoją <strong>przed</strong> słowem, które modyfikują.",
            "examples": [
                {
                    "en": "Ona jest bardzo mądra.",
                    "ua": "Ona jest bardzo bystry."
                },
                {
                    "en": "Biega dość szybko.",
                    "ua": "Biega dość szybko."
                },
                {
                    "en": "Film był wyjątkowo nudny.",
                    "ua": "Фільм був надзвичайно нудним."
                }
            ]
        },
        {
            "label": "A lot, much — в кінці",
            "color": "sky",
            "description": "Прислівники <strong>a lot, much</strong> зазвичай стоять в кінці речення.",
            "examples": [
                {
                    "en": "We travel a lot.",
                    "ua": "Ми багато подорожуємо."
                },
                {
                    "en": "I like it very much.",
                    "ua": "Naprawdę mi się podoba."
                }
            ]
        }
    ]
}

{
    "title": "8. Typowe błędy osób mówiących po ukraińsku",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Sposób przed złożeniem wniosku, a nie po.",
            "wrong": "Ona mówi biegle po angielsku.",
            "right": "​​​​ <span class="font-mono">Ona mówi po angielsku płynnie.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Częstotliwość na początku zamiast przed czasownikiem.",
            "wrong": "Zawsze piję kawę.",
            "right": "]​​​​​​​​​​​​ wcześniej."
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Frequency після дієслова замість перед.",
            "wrong": "Często chodzi na siłownię.",
            "right": " ✅ <span class="font-mono">Często chodzi na siłownię.</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Czas w środku zdanie.",
            "wrong": "Widziałem go wczoraj.",
            "right": " ✅ <span class="font-mono">Widziałem go wczoraj.</span>"
        }
    ]
}

{
    "title": "10. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwą opcję",
    "select_intro": "Wybierz zdanie z właściwym umiejscowieniem przysłówka.",
    "selects": [
        {
            "label": "a) Ona zawsze pije kawę. / b) Ona zawsze pije kawę.",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "a) Mówi biegle po angielsku. / b) Mówi biegle po angielsku.",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "a) Wczoraj go widziałem. / b) Widziałem go wczoraj.",
            "prompt": "Która opcja jest poprawna?"
        }
    ],
    "options": [
        "a",
        "b"
    ],
    "input_title": "Ćwiczenie 2. Wstaw przysłówek we właściwe miejsce",
    "input_intro": "Wstaw przysłówek we właściwe miejsce miejsce.",
    "inputs": [
        {
            "before": "Spóźnia się. (zawsze)",
            "after": "→"
        },
        {
            "before": "Gra na pianinie. (cóż)",
            "after": " →"
        },
        {
            "before": "Działają. / w biurze / szczęśliwy na co dzień.",
            "after": "→"
        }
    ],
    "rephrase_title": "Вправа 3. Виправ помилки",
    "rephrase_intro": "Знайди і виправ помилку у розташуванні прислівника.",
    "rephrase": [
        {
            "example_label": "Приклад:",
            "example_original": "Always he is happy.",
            "example_target": "He is always happy."
        },
        {
            "original": "1. Mówi dobrze po francusku.",
            "placeholder": "Poprawna kolejność słów"
        },
        {
            "original": "2. nigdy nie byłem w Japonii. i okoliczności (aktualne)",
            "placeholder": "Виправ порядок слів"
        }
    ]
}

{
    "title": "Інші сторінки з базової граматики",
    "items": [
        {
            "label": "Basic Word Order — Порядок слів у ствердженні",
            "current": false
        },
        {
            "label": "Word Order in Questions and Negatives — Питання та заперечення",
            "current": false
        },
        {
            "label": "Word Order with Adverbs — Прислівники та обставини (поточна)",
            "current": true
        }
    ]
}
